3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Damage = {
15	  itemType: string;
16	  amount: number;
17	};
18	
19	type Incident = {
20	  cause: string;
21	  damages: Damage[];
22	};
23	
24	type Step = {
25	  op: string;
26	  items?: Item[];
27	  policy?: number;
28	  incident?: Incident;
29	};
30	
31	type ScenarioInput = {
32	  customer: Customer;
33	  steps: Step[];
34	};
35	
36	type QuoteResult = {
37	  premium: number;
38	};
39	
40	type ClaimResult = {
41	  payout: number;
42	  remainingCap: number;
43	};
44	
45	type StepResult = QuoteResult | ClaimResult;
46	
47	type ScenarioOutput = {
48	  results: StepResult[];
49	};
50	
51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_THRESHOLD = 5;
55	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
56	const LOYALTY_YEARS_THRESHOLD = 2;
57	const LOYALTY_DISCOUNT_RATE = 0.2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	const COMPONENT_BLOCK_SIZE = 3;
60	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
61	const DEDUCTIBLE = 100;
62	const HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
63	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
64	const FULL_REIMBURSEMENT_RATE = 1;
65	const CAP_MULTIPLIER = 2;
66	
67	const BASE_PREMIUMS: Record<string, number> = {
68	  sword: 100,
69	  amulet: 60,
70	  staff: 80,
71	  potion: 40,
72	  rune: 25,
73	  moonstone: 25,
74	};
75	
76	const INSURANCE_VALUES: Record<string, number> = {
77	  sword: 1000,
78	  amulet: 600,
79	  rune: 250,
80	};
81	
82	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
83	
84	const isComponentBlock = (type: string, count: number): boolean =>
85	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
86	
87	const basePremiumFor = (type: string): number => {
88	  const basePremium = BASE_PREMIUMS[type];
89	  if (basePremium === undefined) {
90	    throw new Error(`Unknown item type: ${type}`);
91	  }
92	  return basePremium;
93	};
94	
95	const surchargeFor = (
96	  items: Item[],
97	  applies: (item: Item) => boolean,
98	  rate: number
99	): number =>
100	  items.reduce(
101	    (surcharge, item) =>
102	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
103	    0
104	  );
105	
106	const isCursed = (item: Item): boolean => item.cursed === true;
107	
108	const hasEnchantmentAtLeast = (
109	  item: Item | undefined,
110	  threshold: number
111	): boolean => (item?.enchantment ?? 0) >= threshold;
112	
113	const isHighlyEnchanted = (item: Item): boolean =>
114	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
115	
116	const curseSurchargeFor = (items: Item[]): number =>
117	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
118	
119	const enchantmentSurchargeFor = (items: Item[]): number =>
120	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
121	
122	const groupBasePremium = (type: string, count: number): number =>
123	  isComponentBlock(type, count)
124	    ? COMPONENT_BLOCK_BASE_PREMIUM
125	    : count * basePremiumFor(type);
126	
127	const policyBaseFor = (items: Item[]): number => {
128	  const countsByType = new Map<string, number>();
129	  for (const item of items) {
130	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
131	  }
132	
133	  let policyBase = 0;
134	  for (const [type, count] of countsByType) {
135	    policyBase += groupBasePremium(type, count);
136	  }
137	  return policyBase;
138	};
139	
140	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
141	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
142	
143	const quotePremium = (
144	  items: Item[],
145	  customer: Customer,
146	  isFollowUp: boolean
147	): number => {
148	  const policyBase = policyBaseFor(items);
149	  const itemSurcharges =
150	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
151	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
152	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
153	    ? policyBase * LOYALTY_DISCOUNT_RATE
154	    : 0;
155	  const followUpDiscount = isFollowUp
156	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
157	    : 0;
158	  return Math.ceil(
159	    policyBase +
160	      itemSurcharges +
161	      firstInsuranceSurcharge -
162	      loyaltyDiscount -
163	      followUpDiscount +
164	      PROCESSING_FEE
165	  );
166	};
167	
168	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
169	
170	const insuranceSumFor = (items: Item[]): number =>
171	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
172	
173	const reimbursementRateFor = (damagedItem: Item | undefined): number =>
174	  hasEnchantmentAtLeast(damagedItem, HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD)
175	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
176	    : FULL_REIMBURSEMENT_RATE;
177	
178	const payoutForDamage = (damage: Damage, policyItems: Item[]): number => {
179	  const damagedItem = policyItems.find(
180	    (item) => item.type === damage.itemType
181	  );
182	  return damage.amount * reimbursementRateFor(damagedItem) - DEDUCTIBLE;
183	};
184	
185	const processClaim = (step: Step, steps: Step[]): ClaimResult => {
186	  const policyItems = steps[step.policy!].items ?? [];
187	  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
188	  const payout = step.incident!.damages.reduce(
189	    (sum, damage) => sum + payoutForDamage(damage, policyItems),
190	    0
191	  );
192	  return { payout, remainingCap: payoutCap - payout };
193	};
194	
195	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
196	  const results = input.steps.map((step, index) =>
197	    step.op === "claim"
198	      ? processClaim(step, input.steps)
199	      : {
200	          premium: quotePremium(
201	            step.items ?? [],
202	            input.customer,
203	            isFollowUpQuote(index)
204	          ),
205	        }
206	  );
207	  return { results };
208	};
